import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

function HomePage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('http://localhost:8000/api/videos/')
      .then(response => {
        console.log('Загружено видео:', response.data); // Для отладки
        setVideos(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки видео:', error);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div className="card" style={{ padding: 48, textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🎬</div>
          <p>Загрузка видео...</p>
        </div>
      </div>
    );
  }

  return (
    <div>
      <div className="card" style={{ textAlign: 'center', padding: '48px 32px', marginBottom: 32 }}>
        <h1 style={{ fontSize: 'clamp(32px, 5vw, 48px)', fontWeight: 700, marginBottom: 12 }}>
          Видеоплатформа
        </h1>
        <p style={{ fontSize: 18, color: 'var(--text-secondary)' }}>
          Смотрите, загружайте и делитесь видео
        </p>
      </div>

      {videos.length === 0 ? (
        <div className="card" style={{ textAlign: 'center', padding: 64 }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>📭</div>
          <p style={{ fontSize: 18, marginBottom: 24 }}>Пока нет видео</p>
          <Link to="/upload" className="btn btn-primary">
            + Загрузить первое видео
          </Link>
        </div>
      ) : (
        <div className="video-grid">
          {videos.map(video => {
            // Формируем URL для превью
            const videoUrl = video.video_file ? `http://localhost:8000${video.video_file}` : null;
            const thumbnailUrl = video.thumbnail ? `http://localhost:8000${video.thumbnail}` : null;
            
            return (
              <Link to={`/video/${video.id}`} key={video.id} className="video-card">
                <div className="video-thumbnail">
                  {/* Сначала пробуем показать превью-картинку */}
                  {thumbnailUrl ? (
                    <img 
                      src={thumbnailUrl}
                      alt={video.title}
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                      onError={(e) => {
                        // Если картинка не загрузилась, показываем видео
                        e.target.style.display = 'none';
                        const videoEl = document.createElement('video');
                        videoEl.src = videoUrl;
                        videoEl.style.width = '100%';
                        videoEl.style.height = '100%';
                        videoEl.style.objectFit = 'cover';
                        videoEl.muted = true;
                        e.target.parentElement.appendChild(videoEl);
                      }}
                    />
                  ) : videoUrl ? (
                    <video 
                      src={videoUrl}
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                      muted
                    />
                  ) : (
                    <div style={{
                      width: '100%',
                      height: '100%',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: 48,
                      backgroundColor: '#f0f0f0'
                    }}>
                      🎬
                    </div>
                  )}
                </div>
                <div className="video-info">
                  <h3 className="video-title">{video.title}</h3>
                  <p className="video-meta">{video.uploaded_by_name || 'Аноним'} • {video.views || 0} просмотров</p>
                </div>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

export default HomePage;
